+    fn oauth_refresh_invalid_matches_after_redaction() {
+        let cassette_path = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"))
+            .join("tests/fixtures/vcr/oauth_refresh_invalid.json");
